LinK36:
本题的基本方法是采用二分法
⚠️注意：最小预算值一定>=所有预算中最大的预算！
check函数：cnt用于计算组数，sum用于计算每一组的数字之和
将所有预算看成一个数组，每次将数组中的数一个个输入进去求sum。若sum<=limit，则继续往sun中➕预算；反之则组数+1，重新从这个数往下计算sum。
二分法中下限为单日最高预算，上限为所有预算之和，mid = l + (r-l)/2（防止溢出，等价于 (l+r)/2），持续缩小范围，结合check函数的判断最终得出答案
源码：
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
 const int MAXN=100005;
 int a[MAXN];
 int n,m;
 bool check(int limit){
    int cnt=1;
    int sum=0;
    for(int i=0;i<n;++i){
        if(sum+a[i]>limit){
            cnt++;
            sum=a[i];
        }else{
            sum+=a[i];
        }
    }
    return cnt<=m;
 }
 int main(){
     ios::sync_with_stdio(false);
     cin.tie(0);
     cin>>n>>m;
     int l=0,r=0;
     for(int i=0;i<n;++i){
        cin>>a[i];
        l=max(l,a[i]);
        r+=a[i];
     }
     int ans=r;
     while(l<=r){
        int mid=l+(r-l)/2;
        if(check(mid)){
            ans=mid;
            r=mid-1;
        }else{
            l=mid+1;
        }
     }
     cout<<ans<<endl;
     return 0;
 }
